import"./hoisted.BaiF0zRo.js";document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".btn-add-category").forEach(r=>{r.addEventListener("click",o=>{const e=o.currentTarget,t=JSON.parse(e.dataset.product||"{}");if(window.addToCartGlobal){const c=t.id||t.url?.split("/").pop()||t.title.replace(/\s+/g,"-").toLowerCase();window.addToCartGlobal({...t,id:c,quantity:1})}})});const a=document.getElementById("microdosis-sort"),d=document.getElementById("microdosis-grid");a&&d&&a.addEventListener("change",()=>{const r=Array.from(d.querySelectorAll(".product-item")),o=a.value;r.sort((e,t)=>{const c=parseFloat(e.dataset.price?.replace("€","").replace(",",".")||"0"),n=parseFloat(t.dataset.price?.replace("€","").replace(",",".")||"0");return o==="price-asc"?c-n:o==="price-desc"?n-c:0}),r.forEach(e=>d.appendChild(e))})});
